  1→import { storageService } from '../../../core/services/StorageService';
  2→import { StorageKeys } from '../../../core/types/common';
  3→import './styles.css';
  4→
  5→type DefaultModelSetting =
  6→  | { kind: 'id'; id: string; name: string }
  7→  | { kind: 'name'; name: string };
  8→
  9→type StoredDefaultModelSetting = { id: string; name: string };
 10→
 11→// Known Flash/Fast model IDs that should skip auto-selection (page defaults to these)
 12→const FAST_MODEL_IDS = new Set([
 13→  '56fdd199312815e2', // Gemini 2.0 Flash
 14→]);
 15→
 16→// Known Flash/Fast model name patterns (case-insensitive)
 17→const FAST_MODEL_NAMES = ['flash', '2.0 flash', 'gemini 2.0 flash', 'fast', '高速', '高速モード'];
 18→
 19→const CHAT_INPUT_SELECTORS = [
 20→  'main rich-textarea [contenteditable="true"]',
 21→  'rich-textarea [contenteditable="true"]',
 22→  'main div[contenteditable="true"][role="textbox"]',
 23→  'div[contenteditable="true"][role="textbox"]',
 24→  'main .input-area textarea',
 25→  '.input-area textarea',
 26→  'main [contenteditable="true"]',
 27→  'main textarea',
 28→] as const;
