 30→class DefaultModelManager {
 31→  private static instance: DefaultModelManager;
 32→  private observer: MutationObserver | null = null;
 33→  private checkTimer: number | null = null;
 34→  private isLocked = false;
 35→  private currentDefaultModel: DefaultModelSetting | null = null;
 36→  private initialized = false;
 37→  private pendingMenuPanelInjections = new WeakSet<HTMLElement>();
 38→  private menuPanelInjectAttempts = new WeakMap<HTMLElement, number>();
 39→  private started = false;
 40→  private popStateHandler: (() => void) | null = null;
 41→  private originalPushState: History['pushState'] | null = null;
 42→  private originalReplaceState: History['replaceState'] | null = null;
 43→  private lastCheckedPath: string | null = null;
 44→  private sidebarClickHandler: ((e: Event) => void) | null = null;
 45→  private urlCheckTimer: number | null = null;
 46→  // Track if we've already auto-selected for this navigation to prevent duplicates
 47→  private autoSelectSessionId: string | null = null;
 48→  // Track consecutive failures to stop retrying when model is unavailable
 49→  private consecutiveFailures = 0;
 50→  private readonly maxConsecutiveFailures = 3;
 51→
 52→  private constructor() {}
 53→
 54→  public static getInstance(): DefaultModelManager {
 55→    if (!DefaultModelManager.instance) {
 56→      DefaultModelManager.instance = new DefaultModelManager();
 57→    }
 58→    return DefaultModelManager.instance;
 59→  }
 60→
 61→  public async init() {
 62→    if (this.started) return;
 63→    this.started = true;
 64→
 65→    // Initialize cache
 66→    const result = await storageService.get<unknown>(StorageKeys.DEFAULT_MODEL);
 67→    this.currentDefaultModel = result.success ? this.parseStoredDefaultModel(result.data) : null;
 68→    this.initialized = true;
 69→
 70→    this.initObserver();
 71→    void this.checkAndLockModel();
 72→    // Listen for URL changes (SPA navigation)
 73→    this.popStateHandler = () => {
 74→      void this.checkAndLockModelWithDelay();
 75→    };
 76→    window.addEventListener('popstate', this.popStateHandler);
 77→
 78→    // Hack for SPA: hook into history methods
 79→    if (!this.originalPushState) {
 80→      this.originalPushState = history.pushState;
 81→    }
 82→    if (!this.originalReplaceState) {
 83→      this.originalReplaceState = history.replaceState;
 84→    }
 85→
 86→    history.pushState = (...args: Parameters<History['pushState']>) => {
 87→      this.originalPushState?.apply(history, args);
 88→      void this.checkAndLockModelWithDelay();
 89→    };
 90→    history.replaceState = (...args: Parameters<History['replaceState']>) => {
 91→      this.originalReplaceState?.apply(history, args);
 92→      void this.checkAndLockModelWithDelay();
 93→    };
 94→
 95→    // Listen for sidebar "New Chat" link clicks (SPA internal navigation)
 96→    this.sidebarClickHandler = (e: Event) => {
 97→      const target = e.target as HTMLElement;
 98→      // Check if clicked on a link that leads to /app (new conversation) or /gem/ (new gem conversation)
 99→      const link = target.closest('a[href*="/app"]') || target.closest('a[href*="/gem/"]');
100→      if (link) {
101→        // Delay to allow SPA navigation to complete
102→        void this.checkAndLockModelWithDelay();
103→      }
104→    };
105→    document.addEventListener('click', this.sidebarClickHandler, true);
106→
107→    // Periodic URL check as a fallback for edge cases
108→    this.urlCheckTimer = window.setInterval(() => {
109→      const currentPath = window.location.pathname;
110→      if (currentPath !== this.lastCheckedPath && this.isNewConversation()) {
111→        this.lastCheckedPath = currentPath;
112→        void this.checkAndLockModel();
113→      }
114→    }, 500);
115→  }
116→
117→  public destroy(): void {
118→    if (!this.started) return;
119→    this.started = false;
120→
121→    if (this.observer) {
122→      this.observer.disconnect();
123→      this.observer = null;
124→    }
125→
126→    if (this.checkTimer) {
127→      clearInterval(this.checkTimer);
128→      this.checkTimer = null;
129→    }
130→
131→    if (this.urlCheckTimer) {
132→      clearInterval(this.urlCheckTimer);
133→      this.urlCheckTimer = null;
134→    }
135→
136→    if (this.popStateHandler) {
137→      window.removeEventListener('popstate', this.popStateHandler);
138→      this.popStateHandler = null;
139→    }
140→
141→    if (this.sidebarClickHandler) {
142→      document.removeEventListener('click', this.sidebarClickHandler, true);
143→      this.sidebarClickHandler = null;
144→    }
145→
146→    if (this.originalPushState) {
147→      history.pushState = this.originalPushState;
148→      this.originalPushState = null;
149→    }
150→
151→    if (this.originalReplaceState) {
152→      history.replaceState = this.originalReplaceState;
153→      this.originalReplaceState = null;
154→    }
155→
156→    this.pendingMenuPanelInjections = new WeakSet<HTMLElement>();
157→    this.menuPanelInjectAttempts = new WeakMap<HTMLElement, number>();
158→  }
159→
160→  private initObserver() {
161→    // Observe only for the mode switch panel/bottom-sheet being added; Gemini UI triggers many mutations and
162→    // querying the entire document on every mutation can cause severe jank/crashes.
163→    this.observer = new MutationObserver((mutations) => {
164→      for (const mutation of mutations) {
165→        for (const node of Array.from(mutation.addedNodes)) {
166→          if (!(node instanceof HTMLElement)) continue;
167→
168→          const menuPanel = this.resolveModeSwitchContainer(node);
169→
170→          if (menuPanel) {
171→            this.scheduleMenuPanelInjection(menuPanel);
172→          }
173→        }
174→      }
175→    });
176→
177→    this.observer.observe(document.body, { childList: true, subtree: true });
178→  }
179→
180→  private resolveModeSwitchContainer(root: HTMLElement): HTMLElement | null {
181→    if (
182→      root.matches('.mat-mdc-menu-panel.gds-mode-switch-menu[role="menu"]') ||
183→      root.matches('mat-action-list.gds-mode-switch-menu-list') ||
184→      root.matches('.mat-mdc-menu-panel[role="menu"]')
185→    ) {
186→      return root;
187→    }
188→
189→    return (
190→      root.querySelector<HTMLElement>('.mat-mdc-menu-panel.gds-mode-switch-menu[role="menu"]') ??
191→      root.querySelector<HTMLElement>('mat-action-list.gds-mode-switch-menu-list') ??
192→      root.querySelector<HTMLElement>('.mat-mdc-menu-panel[role="menu"]')
193→    );
194→  }
195→
196→  private getModeSwitchMenuPanel(): HTMLElement | null {
197→    return (
198→      document.querySelector<HTMLElement>(
199→        '.mat-mdc-menu-panel.gds-mode-switch-menu[role="menu"]',
200→      ) ??
201→      document.querySelector<HTMLElement>('mat-action-list.gds-mode-switch-menu-list') ??
202→      document.querySelector<HTMLElement>('.mat-mdc-menu-panel[role="menu"]')
203→    );
204→  }
205→
206→  private async waitForModeSwitchMenuPanel(timeoutMs: number): Promise<HTMLElement | null> {
207→    const startedAt = Date.now();
208→    const pollIntervalMs = 50;
209→    while (Date.now() - startedAt < timeoutMs) {
210→      const panel = this.getModeSwitchMenuPanel();
211→      if (panel?.isConnected) return panel;
212→      await new Promise<void>((resolve) => window.setTimeout(resolve, pollIntervalMs));
213→    }
214→    return null;
215→  }
216→
217→  private scheduleMenuPanelInjection(menuPanel: HTMLElement) {
218→    if (this.pendingMenuPanelInjections.has(menuPanel)) return;
219→    this.pendingMenuPanelInjections.add(menuPanel);
220→
221→    const delayMs = 50; // allow menu content to render
222→    window.setTimeout(() => {
223→      if (!this.started) return;
224→
225→      this.pendingMenuPanelInjections.delete(menuPanel);
226→
227→      void this.injectStarButtons(menuPanel).then((didInject) => {
228→        if (didInject) {
229→          this.menuPanelInjectAttempts.delete(menuPanel);
230→          return;
231→        }
232→
233→        if (!menuPanel.isConnected) return;
234→
235→        const attempts = (this.menuPanelInjectAttempts.get(menuPanel) ?? 0) + 1;
236→        this.menuPanelInjectAttempts.set(menuPanel, attempts);
237→
238→        const maxAttempts = 10;
239→        if (attempts < maxAttempts) {
240→          this.scheduleMenuPanelInjection(menuPanel);
241→        }
242→      });
243→    }, delayMs);
244→  }
245→
246→  private async injectStarButtons(menuPanel: HTMLElement): Promise<boolean> {
247→    const items = menuPanel.querySelectorAll('[role="menuitemradio"]');
248→    if (!items.length) return false;
249→
250→    // Use cached value efficiently
251→    if (!this.initialized) {
252→      const result = await storageService.get<unknown>(StorageKeys.DEFAULT_MODEL);
253→      this.currentDefaultModel = result.success ? this.parseStoredDefaultModel(result.data) : null;
254→      this.initialized = true;
255→    }
256→
257→    const currentDefault = this.currentDefaultModel;
258→
259→    items.forEach((item) => {
260→      const modelName = this.getModelNameFromItem(item as HTMLElement);
261→      if (!modelName) return;
262→
263→      // Avoid duplicates
264→      if (item.querySelector('.gv-default-star-btn')) {
265→        // Update state
266→        this.updateStarState(item as HTMLElement, modelName, currentDefault);
267→        return;
268→      }
269→
270→      const btn = document.createElement('button');
271→      btn.className = 'gv-default-star-btn';
272→      btn.innerHTML = this.getStarIcon(false); // Default empty
273→      btn.title = chrome.i18n.getMessage('setAsDefaultModel');
274→
275→      btn.addEventListener('click', async (e) => {
276→        e.stopPropagation(); // Prevent menu item selection
277→        e.preventDefault();
278→        await this.handleStarClick(modelName, btn);
279→      });
280→
281→      // Finding the correct container (title-and-description)
282→      const titleContainer = item.querySelector('.title-and-description');
283→
284→      if (titleContainer) {
285→        const titleEl = titleContainer.querySelector('.mode-title, .gds-title-m, .gds-label-l');
286→        if (titleEl) {
287→          const titleParent = titleEl.parentElement;
288→          let wrapper = titleContainer.querySelector('.gv-title-wrapper') as HTMLElement | null;
289→          if (!wrapper && titleParent?.classList.contains('gv-title-wrapper')) {
290→            wrapper = titleParent;
291→          }
292→
293→          if (!wrapper) {
294→            // Create wrapper
295→            wrapper = document.createElement('div');
296→            wrapper.className = 'gv-title-wrapper';
297→            wrapper.style.cssText = 'display: flex; align-items: center; width: 100%;';
298→
299→            // Insert wrapper where the title currently lives.
300→            if (titleParent) {
301→              titleParent.insertBefore(wrapper, titleEl);
302→            } else {
303→              titleContainer.appendChild(wrapper);
304→            }
305→
306→            // Move title into wrapper
307→            wrapper.appendChild(titleEl);
308→          }
309→
310→          // Append star to wrapper
311→          wrapper.appendChild(btn);
312→        } else {
313→          // Fallback if structure changes
314→          titleContainer.appendChild(btn);
315→        }
316→      } else {
317→        // Fallback
318→        item.appendChild(btn);
319→      }
320→      this.updateStarState(item as HTMLElement, modelName, currentDefault);
321→    });
322→
323→    return true;
324→  }
