326→  private getModelNameFromItem(item: HTMLElement): string {
327→    const titleEl = item.querySelector('.mode-title, .gds-title-m, .gds-label-l');
328→    return titleEl?.textContent?.trim() || '';
329→  }
330→
331→  private getModelIdFromItem(item: HTMLElement): string | null {
332→    const raw = item.getAttribute('data-mode-id') || item.dataset.modeId;
333→    if (typeof raw === 'string') {
334→      const id = raw.trim();
335→      if (id.length) return id;
336→    }
337→
338→    // Compact layout may omit data-mode-id but keeps the internal model id in jslog metadata.
339→    const jslog = item.getAttribute('jslog');
340→    if (typeof jslog === 'string') {
341→      const matchedIds = jslog.match(/[a-f0-9]{16}/gi);
342→      const id = matchedIds?.[matchedIds.length - 1]?.trim();
343→      if (id) return id;
344→    }
345→
346→    return null;
347→  }
348→
349→  private isDefaultForItem(
350→    currentDefault: DefaultModelSetting | null,
351→    item: HTMLElement,
352→    modelName: string,
353→  ): boolean {
354→    if (!currentDefault) return false;
355→    if (currentDefault.kind === 'id') {
356→      const id = this.getModelIdFromItem(item);
357→      return id === currentDefault.id;
358→    }
359→    return currentDefault.name === modelName;
360→  }
361→
362→  private updateStarState(
363→    item: HTMLElement,
364→    modelName: string,
365→    currentDefault: DefaultModelSetting | null,
366→  ) {
367→    const btn = item.querySelector('.gv-default-star-btn') as HTMLElement;
368→    if (!btn) return;
369→
370→    // Ensure mousedown/click stops propagation (idempotent)
371→    if (!btn.hasAttribute('data-event-bound')) {
372→      btn.setAttribute('data-event-bound', 'true');
373→      btn.addEventListener('mousedown', (e) => e.stopPropagation());
374→      btn.addEventListener('click', (e) => e.stopPropagation());
375→    }
376→
377→    const isDefault = this.isDefaultForItem(currentDefault, item, modelName);
378→    if (isDefault) {
379→      btn.classList.add('is-default');
380→      btn.innerHTML = this.getStarIcon(true);
381→      btn.title = chrome.i18n.getMessage('cancelDefaultModel');
382→    } else {
383→      btn.classList.remove('is-default');
384→      btn.innerHTML = this.getStarIcon(false);
385→      btn.title = chrome.i18n.getMessage('setAsDefaultModel');
386→    }
387→  }
388→
389→  private getStarIcon(filled: boolean): string {
390→    if (filled) {
391→      return `<svg viewBox="0 0 24 24"><path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z" fill="currentColor"></path></svg>`;
392→    } else {
393→      return `<svg viewBox="0 0 24 24"><path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z" fill="none" stroke="currentColor" stroke-width="1.5"></path></svg>`;
394→    }
395→  }
