397→  private async handleStarClick(modelName: string, btn: HTMLElement) {
398→    const closestItem = btn.closest('[role="menuitemradio"]');
399→    const modelItem = closestItem instanceof HTMLElement ? closestItem : null;
400→    const modelId = modelItem ? this.getModelIdFromItem(modelItem) : null;
401→
402→    // 1. Optimistic UI Update (Instant feedback)
403→    const isCurrentlyDefault = modelItem
404→      ? this.isDefaultForItem(this.currentDefaultModel, modelItem, modelName)
405→      : this.currentDefaultModel?.kind === 'name'
406→        ? this.currentDefaultModel.name === modelName
407→        : false;
408→
409→    const nextDefault: DefaultModelSetting | null = isCurrentlyDefault
410→      ? null
411→      : modelId
412→        ? { kind: 'id', id: modelId, name: modelName }
413→        : { kind: 'name', name: modelName };
414→
415→    // Update cache immediately
416→    this.currentDefaultModel = nextDefault;
417→
418→    // Update current button immediately
419→    if (modelItem) {
420→      this.updateStarState(modelItem, modelName, nextDefault);
421→    }
422→
423→    // Show Toast immediately
424→    if (nextDefault) {
425→      this.showToast(chrome.i18n.getMessage('defaultModelSet', [modelName]));
426→    } else {
427→      this.showToast(chrome.i18n.getMessage('defaultModelCleared'));
428→    }
429→
430→    // Update other buttons (e.g. if switching from A to B)
431→    const menuPanel = this.getModeSwitchMenuPanel();
432→    if (menuPanel) {
433→      // Re-run injection to update all other buttons based on new cache
434→      void this.injectStarButtons(menuPanel as HTMLElement);
435→    }
436→
437→    // 2. Perform async storage operation in background
438→    if (isCurrentlyDefault) {
439→      await storageService.remove(StorageKeys.DEFAULT_MODEL);
440→    } else {
441→      if (nextDefault?.kind === 'id') {
442→        const toStore: StoredDefaultModelSetting = {
443→          id: nextDefault.id,
444→          name: nextDefault.name,
445→        };
446→        await storageService.set(StorageKeys.DEFAULT_MODEL, toStore);
447→      } else {
448→        await storageService.set(StorageKeys.DEFAULT_MODEL, modelName);
449→      }
450→    }
451→  }
