477→  // ==================== Auto Lock Logic ====================
478→
479→  /**
480→   * Delayed version of checkAndLockModel for SPA navigation.
481→   * Adds a small delay to ensure the URL has actually changed.
482→   */
483→  private async checkAndLockModelWithDelay() {
484→    // Wait for SPA navigation to complete
485→    await new Promise<void>((resolve) => window.setTimeout(resolve, 150));
486→    void this.checkAndLockModel();
487→  }
488→
489→  private async checkAndLockModel() {
490→    // Only lock on new conversation pages
491→    if (!this.isNewConversation()) return;
492→
493→    // Update last checked path
494→    this.lastCheckedPath = window.location.pathname;
495→
496→    const result = await storageService.get<unknown>(StorageKeys.DEFAULT_MODEL);
497→    const targetModel = result.success ? this.parseStoredDefaultModel(result.data) : null;
498→    this.currentDefaultModel = targetModel;
499→    this.initialized = true;
500→
501→    if (!targetModel) return;
502→
503→    // Check if the target model is a Flash/Fast model (default model, skip auto-selection)
504→    if (this.isFastModel(targetModel)) {
505→      return;
506→    }
507→
508→    // Generate a unique session ID to prevent duplicate selections in the same navigation
509→    const sessionId = `${window.location.pathname}-${Date.now()}`;
510→    this.autoSelectSessionId = sessionId;
511→    // Reset failure counter for new session
512→    this.consecutiveFailures = 0;
513→
514→    // Start checking loop
515→    let attempts = 0;
516→    const maxAttempts = 20;
517→
518→    if (this.checkTimer) clearInterval(this.checkTimer);
519→
520→    this.checkTimer = window.setInterval(async () => {
521→      // Abort if session changed (e.g., user navigated away and came back)
522→      if (this.autoSelectSessionId !== sessionId) {
523→        if (this.checkTimer) clearInterval(this.checkTimer);
524→        return;
525→      }
526→
527→      attempts++;
528→      if (attempts > maxAttempts) {
529→        if (this.checkTimer) clearInterval(this.checkTimer);
530→        return;
531→      }
532→
533→      await this.tryLockToModel(targetModel);
534→    }, 1000);
535→  }
536→
537→  private isNewConversation() {
538→    const path = window.location.pathname;
539→    // Supports multi-profile paths like /u/0/app as well as /app.
540→    // Also supports Gem paths like /gem/xyz or /u/0/gem/xyz
541→    return /^\/(u\/\d+\/)?(app\/?|gem\/.*)$/.test(path);
542→  }
543→
544→  /**
545→   * Check if the given model is a Flash/Fast model (Gemini's default model).
546→   * If yes, we don't need to auto-switch since the page already defaults to it.
547→   */
548→  private isFastModel(model: DefaultModelSetting): boolean {
549→    if (model.kind === 'id') {
550→      return FAST_MODEL_IDS.has(model.id);
551→    }
552→    const normalizedName = model.name.toLowerCase().trim();
553→    return FAST_MODEL_NAMES.some(
554→      (fastName) => normalizedName === fastName || normalizedName.includes(fastName),
555→    );
556→  }
557→
558→  private async tryLockToModel(targetModel: DefaultModelSetting) {
559→    // Ported from https://github.com/urzeye/tampermonkey-scripts (Gemini Helper)
560→    const normalize = (s: string) => s.toLowerCase().trim();
561→    const escapeRegExp = (value: string) => value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
562→    const targetName = normalize(targetModel.name);
563→    const targetAsWholeWord = new RegExp(`(^|\\b)${escapeRegExp(targetName)}(\\b|$)`, 'i');
564→
565→    // 1. Find selector button
566→    const selectorBtn =
567→      document.querySelector('.input-area-switch-label') ||
568→      document.querySelector('[data-test-id="model-selector"]') ||
569→      document.querySelector('button[aria-haspopup="menu"].mat-mdc-menu-trigger'); // General fallback
570→
571→    if (!selectorBtn) return;
572→
573→    // 2. Check current model text - early return if already correct
574→    const currentText = selectorBtn.textContent || '';
575→    const normalizedCurrent = normalize(currentText);
576→
577→    // For both 'id' and 'name' kinds, we can check if the button text matches the target name
578→    // This helps avoid unnecessary menu clicks when the model is already selected
579→    if (targetAsWholeWord.test(normalizedCurrent) || normalizedCurrent === targetName) {
580→      // Already correct
581→      if (this.checkTimer) clearInterval(this.checkTimer);
582→      return;
583→    }
584→
585→    // 3. Switch model
586→    // This part is tricky because we need to open the menu and click safely
587→    if (this.isLocked) return; // Prevent concurrent locks
588→    this.isLocked = true;
589→
590→    try {
591→      (selectorBtn as HTMLElement).click();
592→
593→      const menuPanel = await this.waitForModeSwitchMenuPanel(1500);
594→      if (!menuPanel) return;
595→
596→      const items = menuPanel.querySelectorAll('[role="menuitemradio"]');
597→      let found = false;
598→      let switchedModel = false;
599→
600→      if (targetModel.kind === 'id') {
601→        const targetItem = Array.from(items).find((item) => {
602→          if (!(item instanceof HTMLElement)) return false;
603→          return this.getModelIdFromItem(item) === targetModel.id;
604→        });
605→
606→        if (targetItem instanceof HTMLElement) {
607→          const alreadySelected =
608→            targetItem.getAttribute('aria-checked') === 'true' ||
609→            targetItem.classList.contains('is-selected');
610→
611→          if (!alreadySelected) {
612→            targetItem.click();
613→            switchedModel = true;
614→          } else {
615→            // Already selected, close menu to avoid stuck UI
616→            document.body.click();
617→          }
618→
619→          found = true;
620→        }
621→      } else {
622→        for (const item of Array.from(items)) {
623→          const modelName = this.getModelNameFromItem(item as HTMLElement);
624→          if (normalize(modelName) === targetName) {
625→            const alreadySelected =
626→              (item as HTMLElement).getAttribute('aria-checked') === 'true' ||
627→              (item as HTMLElement).classList.contains('is-selected');
628→
629→            if (!alreadySelected) {
630→              (item as HTMLElement).click();
631→              switchedModel = true;
632→            } else {
633→              // Already selected, close menu to avoid stuck UI
634→              document.body.click();
635→            }
636→            found = true;
637→            break;
638→          }
639→        }
640→      }
641→
642→      if (!found) {
643→        // Fallback: whole-word match on the full text content (includes description).
644→        for (const item of Array.from(items)) {
645→          const text = (item as HTMLElement).textContent || '';
646→          if (targetAsWholeWord.test(normalize(text))) {
647→            const alreadySelected =
648→              (item as HTMLElement).getAttribute('aria-checked') === 'true' ||
649→              (item as HTMLElement).classList.contains('is-selected');
650→
651→            if (!alreadySelected) {
652→              (item as HTMLElement).click();
653→              switchedModel = true;
654→            } else {
655→              // Already selected, close menu to avoid stuck UI
656→              document.body.click();
657→            }
658→            found = true;
659→            break;
660→          }
661→        }
662→      }
663→
664→      if (found && this.checkTimer) {
665→        clearInterval(this.checkTimer);
666→        this.consecutiveFailures = 0;
667→      }
668→      if (switchedModel) {
669→        this.focusChatInputAfterAutoSwitch();
670→      }
671→
672→      if (!found) {
673→        // Close menu if not found to avoid stuck menu
674→        document.body.click();
675→
676→        // Track consecutive failures - if model is consistently not found,
677→        // stop trying to avoid endless flashing (e.g., model not available for this account)
678→        this.consecutiveFailures++;
679→        if (this.consecutiveFailures >= this.maxConsecutiveFailures) {
680→          if (this.checkTimer) {
681→            clearInterval(this.checkTimer);
682→          }
683→        }
684→      }
685→    } catch (e) {
686→      console.error('Auto lock failed', e);
687→    } finally {
688→      this.isLocked = false;
689→    }
690→  }
691→
692→  private focusChatInputAfterAutoSwitch(): void {
693→    const focusDelayMs = 120;
694→    window.setTimeout(() => {
695→      const input = this.findChatInputElement();
696→      if (!input) return;
697→
698→      try {
699→        input.focus({ preventScroll: true });
700→      } catch {
701→        input.focus();
702→      }
703→    }, focusDelayMs);
704→  }
705→
706→  private findChatInputElement(): HTMLElement | null {
707→    for (const selector of CHAT_INPUT_SELECTORS) {
708→      const candidates = document.querySelectorAll<HTMLElement>(selector);
709→      for (const candidate of Array.from(candidates)) {
710→        if (!candidate.isConnected) continue;
711→        if (candidate instanceof HTMLTextAreaElement && candidate.disabled) continue;
712→        return candidate;
713→      }
714→    }
715→    return null;
716→  }
717→
718→  private parseStoredDefaultModel(value: unknown): DefaultModelSetting | null {
719→    if (typeof value === 'string') {
720→      const name = value.trim();
721→      return name.length ? { kind: 'name', name } : null;
722→    }
723→
724→    if (this.isStoredDefaultModelSetting(value)) {
725→      const id = value.id.trim();
726→      const name = value.name.trim();
727→      if (!id.length || !name.length) return null;
728→      return { kind: 'id', id, name };
729→    }
730→
731→    return null;
732→  }
733→
734→  private isStoredDefaultModelSetting(value: unknown): value is StoredDefaultModelSetting {
735→    if (typeof value !== 'object' || value === null) return false;
736→    const record = value as Record<string, unknown>;
737→    return typeof record.id === 'string' && typeof record.name === 'string';
738→  }
739→}
