 93→    const result = await chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] });
 94→    const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
 95→      ? result.gvPromptCustomWebsites
 96→      : [];
 97→
 98→    // Normalize current hostname
 99→    const currentHost = location.hostname.toLowerCase().replace(/^www\./, '');
100→
101→    console.log('[Gemini Voyager] Checking custom websites:', {
102→      currentHost,
103→      customWebsites,
104→      hostname: location.hostname,
105→    });
106→
107→    const isCustom = customWebsites.some((website: string) => {
108→      const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
109→      const matches =
110→        currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
111→      console.log('[Gemini Voyager] Comparing:', { currentHost, normalizedWebsite, matches });
112→      return matches;
113→    });
114→
115→    console.log('[Gemini Voyager] Is custom website:', isCustom);
116→    return isCustom;
117→  } catch (e) {
118→    if (isExtensionContextInvalidatedError(e)) {
