126→/**
127→ * Initialize all features sequentially to reduce simultaneous load
128→ */
129→async function initializeFeatures(): Promise<void> {
130→  if (initialized) return;
131→  initialized = true;
132→
133→  try {
134→    if (!hasValidExtensionContext()) {
135→      return;
136→    }
137→    // Sequential initialization with small delays between features
138→    // to further reduce simultaneous resource usage
139→    const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));
140→
141→    // Check if this is a custom website (only prompt manager should be enabled)
142→    const isCustomSite = await isCustomWebsite();
143→
144→    if (isCustomSite) {
145→      // Only start prompt manager for custom websites
146→      console.log('[Gemini Voyager] Custom website detected, starting Prompt Manager only');
147→
148→      promptManagerInstance = await startPromptManager();
149→      return;
150→    }
151→
152→    console.log('[Gemini Voyager] Not a custom website, checking for Gemini/AI Studio');
153→
154→    const isEnterprise = isGeminiEnterpriseEnvironment(
155→      {
156→        hostname: location.hostname,
157→        pathname: location.pathname,
