191→      await delay(LIGHT_FEATURE_INIT_DELAY);
192→
193→      startSnowEffect();
194→      startSakuraEffect();
195→      startRainEffect();
196→      await delay(LIGHT_FEATURE_INIT_DELAY);
197→
198→      startInputCollapse();
199→      await delay(LIGHT_FEATURE_INIT_DELAY);
200→
201→      startPreventAutoScroll();
202→      await delay(LIGHT_FEATURE_INIT_DELAY);
203→
204→      startFormulaCopy();
205→
206→      await delay(LIGHT_FEATURE_INIT_DELAY);
