308→/**
309→ * Determine initialization delay based on tab visibility
310→ */
311→function getInitializationDelay(): number {
312→  // Check if tab is currently visible
313→  const isVisible = document.visibilityState === 'visible';
314→
315→  if (isVisible) {
316→    // Foreground tab: initialize immediately for good UX
317→    console.log('[Gemini Voyager] Foreground tab detected, initializing immediately');
318→    return 0;
319→  } else {
320→    // Background tab: add random delay to distribute load across multiple tabs
321→    const randomRange = BACKGROUND_TAB_MAX_DELAY - BACKGROUND_TAB_MIN_DELAY;
322→    const randomDelay = BACKGROUND_TAB_MIN_DELAY + Math.random() * randomRange;
323→    console.log(
324→      `[Gemini Voyager] Background tab detected, delaying initialization by ${Math.round(randomDelay)}ms`,
325→    );
326→    return randomDelay;
327→  }
328→}
329→
330→/**
331→ * Handle tab visibility changes
332→ */
333→function handleVisibilityChange(): void {
334→  if (document.visibilityState === 'visible' && !initialized) {
335→    // Tab became visible before initialization completed
336→    // Cancel any pending delayed initialization and start immediately
337→    if (initializationTimer !== null) {
338→      clearTimeout(initializationTimer);
339→      initializationTimer = null;
340→      console.log('[Gemini Voyager] Tab became visible, initializing immediately');
341→    }
342→    initializeFeatures();
343→  }
344→}
345→
346→// Main initialization logic
347→(function () {
348→  try {
349→    if (!hasValidExtensionContext()) return;
350→
351→    const onUnhandledRejection = (event: PromiseRejectionEvent) => {
352→      if (isExtensionContextInvalidatedError(event.reason)) {
353→        event.preventDefault();
354→      }
355→    };
356→    const onWindowError = (event: ErrorEvent) => {
357→      if (isExtensionContextInvalidatedError(event.error ?? event.message)) {
358→        event.preventDefault();
359→      }
360→    };
361→    window.addEventListener('unhandledrejection', onUnhandledRejection);
362→    window.addEventListener('error', onWindowError);
363→    const onStorageChanged = (
364→      changes: Record<string, chrome.storage.StorageChange>,
365→      areaName: string,
366→    ) => {
367→      if (
368→        (areaName !== 'sync' && areaName !== 'local') ||
369→        location.hostname !== 'gemini.google.com'
370→      ) {
371→        return;
372→      }
373→
374→      const forkSetting = changes[StorageKeys.FORK_ENABLED];
375→      if (!forkSetting) return;
376→
377→      const enabled = isForkFeatureEnabledValue(forkSetting.newValue);
378→      if (enabled) {
379→        if (!forkCleanup) {
380→          forkCleanup = startFork();
381→        }
382→      } else if (forkCleanup) {
383→        forkCleanup();
384→        forkCleanup = null;
385→      }
386→    };
387→
388→    // Quick check: only run on supported websites
389→    const hostname = location.hostname.toLowerCase();
390→    const isSupportedSite =
391→      hostname.includes('gemini.google.com') ||
392→      hostname.includes('business.gemini.google') ||
393→      hostname.includes('aistudio.google.com') ||
394→      hostname.includes('aistudio.google.cn');
395→
396→    // Initialize KaTeX configuration early to suppress Unicode warnings
397→    // This must run before any formulas are rendered on the page
398→    if (isSupportedSite) {
399→      initKaTeXConfig();
400→      // Initialize i18n early to ensure translations are available
401→      initI18n().catch((e) => console.error('[Gemini Voyager] i18n init error:', e));
402→    }
403→
404→    // If not a known site, check if it's a custom website (async)
405→    if (!isSupportedSite) {
406→      // For unknown sites, check storage asynchronously
407→      chrome.storage?.sync?.get({ gvPromptCustomWebsites: [] }, (result) => {
408→        const customWebsites = Array.isArray(result?.gvPromptCustomWebsites)
409→          ? result.gvPromptCustomWebsites
410→          : [];
411→        const currentHost = hostname.replace(/^www\./, '');
412→
413→        const isCustomSite = customWebsites.some((website: string) => {
414→          const normalizedWebsite = website.toLowerCase().replace(/^www\./, '');
415→          return currentHost === normalizedWebsite || currentHost.endsWith('.' + normalizedWebsite);
416→        });
417→
418→        if (isCustomSite) {
419→          console.log('[Gemini Voyager] Custom website detected:', hostname);
420→          initializeFeatures();
421→        } else {
422→          // Not a supported site, exit early
423→          console.log('[Gemini Voyager] Not a supported website, skipping initialization');
424→        }
425→      });
426→      return;
427→    }
428→    chrome.storage?.onChanged?.addListener(onStorageChanged);
429→
430→    const delay = getInitializationDelay();
431→
432→    if (delay === 0) {
433→      // Immediate initialization for foreground tabs
434→      initializeFeatures();
435→    } else {
436→      // Delayed initialization for background tabs
437→      initializationTimer = window.setTimeout(() => {
438→        initializationTimer = null;
439→        initializeFeatures();
440→      }, delay);
441→    }
442→
443→    // Listen for visibility changes to handle tab switching
444→    document.addEventListener('visibilitychange', handleVisibilityChange);
445→
446→    // Setup cleanup on page unload to prevent memory leaks
447→    window.addEventListener('beforeunload', () => {
448→      try {
449→        window.removeEventListener('unhandledrejection', onUnhandledRejection);
450→        window.removeEventListener('error', onWindowError);
451→        if (folderManagerInstance) {
452→          folderManagerInstance.destroy();
453→          folderManagerInstance = null;
454→        }
455→        if (promptManagerInstance) {
456→          promptManagerInstance.destroy();
457→          promptManagerInstance = null;
458→        }
459→        if (quoteReplyCleanup) {
460→          quoteReplyCleanup();
461→          quoteReplyCleanup = null;
462→        }
463→        if (sendBehaviorCleanup) {
464→          sendBehaviorCleanup();
465→          sendBehaviorCleanup = null;
466→        }
467→        if (forkCleanup) {
468→          forkCleanup();
469→          forkCleanup = null;
470→        }
471→        chrome.storage?.onChanged?.removeListener(onStorageChanged);
472→      } catch (e) {
473→        if (isExtensionContextInvalidatedError(e)) {
474→          return;
475→        }
476→        console.error('[Gemini Voyager] Cleanup error:', e);
477→      }
478→    });
479→  } catch (e) {
480→    if (isExtensionContextInvalidatedError(e)) {
481→      return;
482→    }
483→    console.error('[Gemini Voyager] Fatal initialization error:', e);
484→  }
485→})();
