```typescript
private async tryLockToModel(targetModel: DefaultModelSetting) {
  // 1. Find selector button
  const selectorBtn = document.querySelector('.input-area-switch-label') || ...;

  // 2. Check if already correct (early return)
  const currentText = selectorBtn.textContent || '';
  if (targetAsWholeWord.test(normalize(currentText))) return;

  // 3. Click to open menu
  (selectorBtn as HTMLElement).click();

  // 4. Wait for menu panel
  const menuPanel = await this.waitForModeSwitchMenuPanel(1500);

  // 5. Find target model item
  // - First try: match by ID (if stored as 'id' kind)
  // - Second try: match by name (exact/normalized)
  // - Third try: regex whole-word match on full text

  // 6. Click target item (if not already selected)
  targetItem.click();

  // 7. Focus chat input
  this.focusChatInputAfterAutoSwitch();

  // 8. Track failures (stop after 3 consecutive failures)
  this.consecutiveFailures++;
  if (this.consecutiveFailures >= 3) {
    clearInterval(this.checkTimer);
  }
}
```

#### **Matching Strategies** (lines 600-662)

1. **By ID** (preferred, language-independent):
   ```typescript
   if (targetModel.kind === 'id') {
     const targetItem = Array.from(items).find((item) =>
       this.getModelIdFromItem(item) === targetModel.id
     );
   }
   ```

2. **By normalized name**:
   ```typescript
   const normalize = (s: string) => s.toLowerCase().trim();
   const targetName = normalize(targetModel.name);
   for (const item of Array.from(items)) {
     const modelName = this.getModelNameFromItem(item as HTMLElement);
     if (normalize(modelName) === targetName) { ... }
   }
   ```

3. **By whole-word regex match** (fallback, handles descriptions):
   ```typescript
   const targetAsWholeWord = new RegExp(`(^|\\b)${escapeRegExp(targetName)}(\\b|$)`, 'i');
   for (const item of Array.from(items)) {
     const text = (item as HTMLElement).textContent || '';
     if (targetAsWholeWord.test(normalize(text))) { ... }
   }
   ```

**Key insight**: Regex matching avoids false positives like matching "Pro" inside "Problems".

