477→  // ==================== Auto Lock Logic ====================
478→
479→  /**
480→   * Delayed version of checkAndLockModel for SPA navigation.
481→   * Adds a small delay to ensure the URL has actually changed.
482→   */
483→  private async checkAndLockModelWithDelay() {
484→    // Wait for SPA navigation to complete
485→    await new Promise<void>((resolve) => window.setTimeout(resolve, 150));
486→    void this.checkAndLockModel();
